//! The purpose of this binary is to perform a single run of the primitive under test so that
//! its peak memory usage can be measured with:
//!
//!     valgrind --tool=massif --heap=no --stacks=yes -- target/release/bench_mldsa_mem_usage > /dev/null
//!
//!     ms_print massif.out.835000
//!
//! or, shoved all into one line:
//!
//!     clear; clear; valgrind --tool=massif --heap=no --stacks=yes -- target/release/bench_mldsa_mem_usage > /dev/null; ms_print massif.out.*; rm massif.out.*
//!
//! Make sure you build in release mode!
//!
//! Note: I'm using print!() to force the compiler not to optimize away the actual code.
//! I'm printing the important stuff for benchmarking to stderr so that I can pipe the junk to /dev/null
//! (I'm not doing it the other way because /usr/bin/time prints its useful stuff to stderr as well)
//!
//! Main is at the bottom, controls which this was actually run.

#![allow(dead_code)]
#![allow(unused_imports)]

use bouncycastle::core::key_material::{KeyMaterial256, KeyType};
use bouncycastle::core::traits::{SignaturePrivateKey, SignaturePublicKey, SignatureVerifier};
use bouncycastle::hex;
use bouncycastle::mldsa::MLDSA44_SIG_LEN;

/// This prints the in-memory size of all the public and private key structs
fn print_struct_sizes() {
    use bouncycastle::mldsa;
    use bouncycastle::mldsa_lowmemory;
    use core::mem::size_of;

    println!("\nML-DSA-44");
    println!("size_of<mldsa::MLDSA44PublicKey>: {}", size_of::<mldsa::MLDSA44PublicKey>());
    println!(
        "size_of<mldsa::MLDSA44PublicKeyExpanded>: {}",
        size_of::<mldsa::MLDSA44PublicKeyExpanded>()
    );
    println!("size_of<mldsa::MLDSA44PrivateKey>: {}", size_of::<mldsa::MLDSA44PrivateKey>());
    println!(
        "size_of<mldsa::MLDSA44PrivateKeyExpanded>: {}",
        size_of::<mldsa::MLDSA44PrivateKeyExpanded>()
    );

    println!("\nML-DSA-65");
    println!("size_of<mldsa::MLDSA65PublicKey>: {}", size_of::<mldsa::MLDSA65PublicKey>());
    println!(
        "size_of<mldsa::MLDSA65PublicKeyExpanded>: {}",
        size_of::<mldsa::MLDSA65PublicKeyExpanded>()
    );
    println!("size_of<mldsa::MLDSA65PrivateKey>: {}", size_of::<mldsa::MLDSA65PrivateKey>());
    println!(
        "size_of<mldsa::MLDSA65PrivateKeyExpanded>: {}",
        size_of::<mldsa::MLDSA65PrivateKeyExpanded>()
    );

    println!("\nML-DSA-87");
    println!("size_of<mldsa::MLDSA87PublicKey>: {}", size_of::<mldsa::MLDSA87PublicKey>());
    println!(
        "size_of<mldsa::MLDSA87PublicKeyExpanded>: {}",
        size_of::<mldsa::MLDSA87PublicKeyExpanded>()
    );
    println!("size_of<mldsa::MLDSA87PrivateKey>: {}", size_of::<mldsa::MLDSA87PrivateKey>());
    println!(
        "size_of<mldsa::MLDSA87PrivateKeyExpanded>: {}",
        size_of::<mldsa::MLDSA87PrivateKeyExpanded>()
    );

    println!("\n\nlowmemory");

    println!("\nML-KEM-512_lowmemory");
    println!(
        "size_of<mldsa_lowmemory::MLDSA44PublicKey>: {}",
        size_of::<mldsa_lowmemory::MLDSA44PublicKey>()
    );
    println!(
        "size_of<mldsa_lowmemory::MLDSA44PrivateKey>: {}",
        size_of::<mldsa_lowmemory::MLDSA44PrivateKey>()
    );

    println!("\nML-KEM-768_lowmemory");
    println!(
        "size_of<mldsa_lowmemory::MLDSA65PublicKey>: {}",
        size_of::<mldsa_lowmemory::MLDSA65PublicKey>()
    );
    println!(
        "size_of<mldsa_lowmemory::MLDSA65PrivateKey>: {}",
        size_of::<mldsa_lowmemory::MLDSA65PrivateKey>()
    );

    println!("\nML-KEM-1024_lowmemory");
    println!(
        "size_of<mldsa_lowmemory::MLDSA87PublicKey>: {}",
        size_of::<mldsa_lowmemory::MLDSA87PublicKey>()
    );
    println!(
        "size_of<mldsa_lowmemory::MLDSA87PrivateKey>: {}",
        size_of::<mldsa_lowmemory::MLDSA87PrivateKey>()
    );
}

/// This exists so I can use /usr/bin/time to measure the base memory footprint of the cargo bench harness
fn bench_do_nothing() {
    eprintln!("DoNothing");

    print!("{}", 1 + 1);
}

fn bench_mldsa44_keygen() {
    use bouncycastle::mldsa::{MLDSA44, MLDSATrait};

    eprintln!("MLDSA44/KeyGen");

    let seed = KeyMaterial256::from_bytes_as_type(
        &[
            0x00, 0x01, 0x02, 0x03, 0x04, 0x05, 0x06, 0x07, 0x08, 0x09, 0x0A, 0x0B, 0x0C, 0x0D,
            0x0E, 0x0F, 0x10, 0x11, 0x12, 0x13, 0x14, 0x15, 0x16, 0x17, 0x18, 0x19, 0x1A, 0x1B,
            0x1C, 0x1D, 0x1E, 0x1F,
        ],
        KeyType::Seed,
    )
    .unwrap();

    let (pk, _sk) = MLDSA44::keygen_from_seed(&seed).unwrap();
    println!("{:x?}", pk.encode());
}

